
#include "svg_helper.h"
int main(){string stem="14_sorting_summary",title="14 Sorting Summary"; vector<string> alg={"Bubble","Selection","Insertion","Quick","Merge"}; vector<string> f={"compare stability","compare in-place property","compare average/worst time","choose algorithm by situation"}; for(int k=0;k<6;++k){int W=1140,H=680; string s=startSVG(W,H,title,"Step "+to_string(k+1)+" / 6 - compare sorting algorithms"); s+=box(50,120,610,400,"#fff","#bfd3e6"); s+=T(90,155,"Sorting summary: same problem, different behavior",17,"#123","700"); s+=T(100,200,"Algorithm",15,"#123","700")+T(240,200,"Average",15,"#123","700")+T(360,200,"Stable",15,"#123","700")+T(470,200,"In-place",15,"#123","700"); vector<string> avg={"O(n^2)","O(n^2)","O(n^2)","O(n log n)","O(n log n)"}; vector<string> stable={"Yes","No","Yes","No","Yes"}; vector<string> inplace={"Yes","Yes","Yes","Yes","No"}; for(int i=0;i<5;i++){string fill=i==k-1?"#fee2e2":"#ffffff"; s+=box(90,220+i*55,500,42,fill,"#cbd5e1"); s+=T(105,247+i*55,alg[i],15); s+=T(240,247+i*55,avg[i],15); s+=T(365,247+i*55,stable[i],15); s+=T(480,247+i*55,inplace[i],15);} if(k==5) s+=T(100,535,"考試重點：不要只背複雜度，還要能手算每一輪陣列狀態。",16,"#b91c1c","700"); s+=sidebar(k+1,6,f)+footer(W,H,stem+".cpp"); stringstream p; p<<"output/"<<stem<<"_steps/step_"<<setw(2)<<setfill('0')<<k+1<<".svg"; writeFile(p.str(),s+endSVG());}}
